/**
 * AIM Workshop — Download as PDF
 * Generates a branded PDF with embedded AIM logo.
 * Requires jsPDF loaded via CDN before this script.
 */
(function () {
  var BLUE  = [46, 61, 125];
  var WHITE = [255, 255, 255];
  var CREAM = [241, 238, 222];
  var MUTED = [130, 135, 160];
  var ACCENT = [109, 216, 255];
  var DARK  = [40, 44, 60];

  var PAGE_W = 210;
  var PAGE_H = 297;
  var MARGIN = 20;
  var CONTENT_W = PAGE_W - MARGIN * 2;
  var y = 0;

  /* ── Embedded logos (base64) ── */
  var AIM_LOGO = 'data:image/png;base64,';
  var COS_LOGO = 'data:image/png;base64,';

  function needsNewPage(doc, needed) {
    if (y + needed > PAGE_H - 25) {
      doc.addPage();
      y = MARGIN;
      return true;
    }
    return false;
  }

  function drawHeader(doc, title, subtitle) {
    doc.setFillColor(BLUE[0], BLUE[1], BLUE[2]);
    doc.rect(0, 0, PAGE_W, 48, 'F');

    /* AIM logo left */
    try { doc.addImage(AIM_LOGO, 'PNG', MARGIN, 7, 32, 13); } catch (e) {
      doc.setTextColor(255,255,255); doc.setFontSize(14); doc.setFont('helvetica','bold'); doc.text('AIM', MARGIN, 17);
    }

    /* Accent line */
    doc.setDrawColor(ACCENT[0], ACCENT[1], ACCENT[2]);
    doc.setLineWidth(0.4);
    doc.line(MARGIN, 24, PAGE_W - MARGIN, 24);

    /* Title */
    doc.setTextColor(255, 255, 255);
    doc.setFontSize(15);
    doc.setFont('helvetica', 'bold');
    var titleLines = doc.splitTextToSize(title, CONTENT_W);
    doc.text(titleLines, MARGIN, 33);

    if (subtitle) {
      doc.setFontSize(8); doc.setFont('helvetica', 'normal');
      doc.setTextColor(ACCENT[0], ACCENT[1], ACCENT[2]);
      doc.text(subtitle, PAGE_W - MARGIN, 31, { align: 'right' });
    }
    doc.setFontSize(7); doc.setTextColor(200, 200, 220);
    doc.text(new Date().toLocaleDateString('en-AU', { day:'numeric', month:'long', year:'numeric' }), PAGE_W - MARGIN, 38, { align:'right' });

    doc.setFillColor(CREAM[0], CREAM[1], CREAM[2]);
    doc.rect(0, 48, PAGE_W, 3, 'F');
    y = 58;
  }

  function drawSectionTitle(doc, text) {
    needsNewPage(doc, 18);
    y += 2;
    doc.setFillColor(CREAM[0], CREAM[1], CREAM[2]);
    doc.roundedRect(MARGIN, y, CONTENT_W, 10, 2, 2, 'F');
    doc.setTextColor(BLUE[0], BLUE[1], BLUE[2]);
    doc.setFontSize(11); doc.setFont('helvetica', 'bold');
    doc.text(text, MARGIN + 4, y + 7);
    y += 16;
  }

  function drawParagraph(doc, text, style) {
    if (!text || text.trim().length < 3) return;
    text = text.trim();
    needsNewPage(doc, 12);
    if (style === 'muted') {
      doc.setTextColor(MUTED[0], MUTED[1], MUTED[2]);
      doc.setFontSize(9); doc.setFont('helvetica', 'italic');
    } else {
      doc.setTextColor(DARK[0], DARK[1], DARK[2]);
      doc.setFontSize(9); doc.setFont('helvetica', 'normal');
    }
    var lines = doc.splitTextToSize(text, CONTENT_W);
    lines.forEach(function (line) {
      needsNewPage(doc, 6);
      doc.text(line, MARGIN, y + 3);
      y += 5.5;
    });
    y += 3;
  }

  function drawLabel(doc, text) {
    needsNewPage(doc, 10);
    doc.setTextColor(MUTED[0], MUTED[1], MUTED[2]);
    doc.setFontSize(8); doc.setFont('helvetica', 'bold');
    doc.text(text.toUpperCase(), MARGIN, y + 3);
    y += 7;
  }

  function drawValue(doc, text) {
    needsNewPage(doc, 12);
    doc.setTextColor(DARK[0], DARK[1], DARK[2]);
    doc.setFontSize(10); doc.setFont('helvetica', 'normal');
    if (!text || text.trim() === '') { doc.setTextColor(180,180,180); text = '(not filled in)'; }
    var lines = doc.splitTextToSize(text, CONTENT_W - 4);
    lines.forEach(function (line) {
      needsNewPage(doc, 7);
      doc.text(line, MARGIN + 2, y + 3);
      y += 6;
    });
    y += 3;
  }

  function drawDivider(doc) {
    needsNewPage(doc, 4);
    doc.setDrawColor(220, 220, 225);
    doc.setLineWidth(0.3);
    doc.line(MARGIN, y, PAGE_W - MARGIN, y);
    y += 5;
  }

  function drawBullet(doc, text) {
    if (!text || text.trim().length < 3) return;
    text = text.trim();
    needsNewPage(doc, 10);
    doc.setFillColor(BLUE[0], BLUE[1], BLUE[2]);
    doc.circle(MARGIN + 2, y + 2, 1.2, 'F');
    doc.setTextColor(DARK[0], DARK[1], DARK[2]);
    doc.setFontSize(9); doc.setFont('helvetica', 'normal');
    var lines = doc.splitTextToSize(text, CONTENT_W - 10);
    lines.forEach(function (line) {
      needsNewPage(doc, 6);
      doc.text(line, MARGIN + 7, y + 3);
      y += 5.5;
    });
    y += 1;
  }

  function drawCard(doc, heading, body) {
    needsNewPage(doc, 18);
    var bodyLines = body ? doc.splitTextToSize(body, CONTENT_W - 14) : [];
    var cardH = (heading ? 9 : 0) + bodyLines.length * 5 + 6;
    needsNewPage(doc, cardH + 4);
    doc.setFillColor(248, 247, 244);
    doc.roundedRect(MARGIN + 2, y, CONTENT_W - 4, cardH, 2, 2, 'F');
    doc.setDrawColor(230, 228, 220); doc.setLineWidth(0.2);
    doc.roundedRect(MARGIN + 2, y, CONTENT_W - 4, cardH, 2, 2, 'S');
    if (heading) {
      doc.setTextColor(BLUE[0], BLUE[1], BLUE[2]);
      doc.setFontSize(9); doc.setFont('helvetica', 'bold');
      doc.text(heading, MARGIN + 6, y + 6);
      y += 9;
    }
    if (bodyLines.length > 0) {
      doc.setTextColor(DARK[0], DARK[1], DARK[2]);
      doc.setFontSize(8); doc.setFont('helvetica', 'normal');
      bodyLines.forEach(function (line) { doc.text(line, MARGIN + 6, y + 3); y += 5; });
    }
    y += 5;
  }

  function drawFooter(doc) {
    var n = doc.internal.getNumberOfPages();
    for (var i = 1; i <= n; i++) {
      doc.setPage(i);
      doc.setDrawColor(BLUE[0], BLUE[1], BLUE[2]);
      doc.setLineWidth(0.5);
      doc.line(MARGIN, PAGE_H - 15, PAGE_W - MARGIN, PAGE_H - 15);
      doc.setTextColor(MUTED[0], MUTED[1], MUTED[2]);
      doc.setFontSize(7); doc.setFont('helvetica', 'normal');
      doc.text('AIM AI Bootcamp for Small Business', MARGIN, PAGE_H - 10);
      doc.text('Page ' + i + ' of ' + n, PAGE_W - MARGIN, PAGE_H - 10, { align:'right' });
    }
  }

  function getVisibleText(el) {
    if (!el) return '';
    var skip = ['SCRIPT','STYLE','SVG','NAV','BUTTON','INPUT','TEXTAREA','SELECT'];
    if (skip.indexOf(el.tagName) > -1) return '';
    if (el.classList && (el.classList.contains('cs-thumb') || el.classList.contains('module-dot') || el.classList.contains('gl-tip'))) return '';
    var t = '';
    el.childNodes.forEach(function (n) {
      if (n.nodeType === 3) t += n.textContent;
      else if (n.nodeType === 1) t += getVisibleText(n);
    });
    return t;
  }

  window.downloadWorkshopPDF = function () {
    if (typeof window.jspdf === 'undefined') { alert('PDF library is loading, please try again in a moment.'); return; }
    var btn = document.querySelector('[onclick*="downloadWorkshopPDF"]');
    var btnText = '';
    if (btn) { btnText = btn.innerHTML; btn.innerHTML = 'Generating…'; btn.disabled = true; }
    try { generatePDF(); } catch (e) { console.error('PDF error:', e); alert('Error generating PDF.'); }
    if (btn) { btn.innerHTML = btnText; btn.disabled = false; }
  };

  function generatePDF() {
    var jsPDF = window.jspdf.jsPDF;
    var doc = new jsPDF({ unit:'mm', format:'a4' });

    var pageTitle = document.querySelector('h1') ? document.querySelector('h1').textContent.trim() : 'Workshop';
    var courseName = '';
    if (document.body.classList.contains('course-business')) courseName = 'AI for Business';
    else if (document.body.classList.contains('course-marketing')) courseName = 'AI for Marketing';
    else courseName = 'AI Bootcamp';

    drawHeader(doc, pageTitle, courseName);

    var mainEl = document.querySelector('main');
    if (mainEl) {
      var introEls = mainEl.querySelectorAll(':scope > p, :scope > div > p');
      introEls.forEach(function (p) {
        if (p.closest('section')) return;
        var txt = p.textContent.trim();
        if (txt.length > 5) drawParagraph(doc, txt, 'muted');
      });
    }

    var sections = document.querySelectorAll('main section');
    sections.forEach(function (section) {
      var h = section.querySelector('h2, h3');
      var sectionTitle = h ? h.textContent.trim() : '';
      var lower = sectionTitle.toLowerCase();
      if (lower.indexOf('cheat sheet') > -1) return;
      if (lower.indexOf('related') > -1 && lower.indexOf('cheat') > -1) return;
      if (section.querySelector('[onclick*="downloadWorkshopPDF"]')) return;

      if (sectionTitle) drawSectionTitle(doc, sectionTitle);

      var sectionP = section.querySelectorAll(':scope > p, :scope > div > p');
      sectionP.forEach(function (p) {
        if (p.closest('table') || p.closest('.glass-light') || p.closest('.glass')) return;
        var txt = p.textContent.trim();
        if (txt && txt.length > 5) drawParagraph(doc, txt, 'muted');
      });

      var cards = section.querySelectorAll('.glass, .glass-light');
      cards.forEach(function (card) {
        if (card.querySelector('.aspect-\\[3\\/4\\]') || card.querySelector('img[src*="cheatsheet"]') || card.querySelector('img[src*="cheat"]')) return;
        if (card.tagName === 'A' && card.getAttribute('href') && card.getAttribute('href').indexOf('.html') > -1) return;
        var cardH3 = card.querySelector('h3, .font-semibold, .font-bold');
        var heading = cardH3 ? cardH3.textContent.trim() : '';
        var bodyText = '';
        card.querySelectorAll('p').forEach(function (p) {
          var t = p.textContent.trim();
          if (t && t !== heading && t.length > 2) bodyText += (bodyText ? ' ' : '') + t;
        });
        card.querySelectorAll('li').forEach(function (li) {
          var t = li.textContent.trim();
          if (t) bodyText += (bodyText ? '\n' : '') + '  •  ' + t;
        });
        if (heading || bodyText) {
          if (heading && bodyText) drawCard(doc, heading, bodyText);
          else if (heading) drawBullet(doc, heading);
          else if (bodyText && bodyText.length < 300) drawBullet(doc, bodyText);
        }
      });

      var lists = section.querySelectorAll(':scope > ul > li, :scope > ol > li, :scope > div > ul > li, :scope > div > ol > li');
      lists.forEach(function (li) {
        if (li.closest('.glass') || li.closest('.glass-light')) return;
        var txt = li.textContent.trim();
        if (txt && txt.length > 3) drawBullet(doc, txt);
      });

      var tables = section.querySelectorAll('table');
      tables.forEach(function (table) {
        var headers = [];
        table.querySelectorAll('thead th').forEach(function (th) { headers.push(th.textContent.trim()); });
        var nCols = headers.length || 1;
        var colWidths = [];
        if (nCols >= 4) {
          var firstW = CONTENT_W * 0.4;
          var restW = (CONTENT_W - firstW) / (nCols - 1);
          colWidths.push(firstW);
          for (var _c = 1; _c < nCols; _c++) colWidths.push(restW);
        } else {
          for (var _c = 0; _c < nCols; _c++) colWidths.push(CONTENT_W / nCols);
        }
        function colX(idx) { var x = MARGIN; for (var _j = 0; _j < idx; _j++) x += colWidths[_j]; return x; }
        if (headers.length > 0) {
          needsNewPage(doc, 14);
          doc.setFillColor(BLUE[0], BLUE[1], BLUE[2]);
          doc.rect(MARGIN, y, CONTENT_W, 8, 'F');
          doc.setTextColor(255,255,255); doc.setFontSize(7); doc.setFont('helvetica','bold');
          headers.forEach(function (h, i) { doc.text(doc.splitTextToSize(h, colWidths[i]-4)[0], colX(i) + 2, y + 5.5); });
          y += 10;
        }
        table.querySelectorAll('tbody tr').forEach(function (tr, rowIdx) {
          needsNewPage(doc, 10);
          if (rowIdx % 2 === 0) { doc.setFillColor(248,248,250); doc.rect(MARGIN, y-1, CONTENT_W, 8, 'F'); }
          var cells = tr.querySelectorAll('td');
          doc.setTextColor(DARK[0], DARK[1], DARK[2]); doc.setFontSize(8); doc.setFont('helvetica','normal');
          cells.forEach(function (td, i) {
            var input = td.querySelector('input, select, textarea');
            var val = input ? (input.value || '') : td.textContent.trim();
            if (!val && input && input.placeholder) val = input.placeholder;
            var cw = (i < colWidths.length) ? colWidths[i] : (CONTENT_W / nCols);
            var lines = doc.splitTextToSize(val, cw - 4);
            doc.text(lines[0], colX(i) + 2, y + 4.5);
          });
          y += 8;
        });
        y += 4;
      });

      var inputs = section.querySelectorAll('input[type="text"], textarea, select');
      inputs.forEach(function (input) {
        if (input.closest('table')) return;
        var label = '';
        var wrapper = input.closest('.glass, .glass-light, div');
        if (wrapper) { var le = wrapper.querySelector('span.text-sm, label, .font-semibold'); if (le && le.textContent.trim().length < 120) label = le.textContent.trim(); }
        if (!label) { var prev = input.previousElementSibling; if (prev && prev.textContent) label = prev.textContent.trim(); }
        if (!label && input.placeholder) label = input.placeholder;
        if (!label && input.id) label = input.id.replace(/-/g, ' ');
        if (label) drawLabel(doc, label);
        var val = input.value || '';
        if (input.tagName === 'SELECT') val = input.options[input.selectedIndex] ? input.options[input.selectedIndex].text : '';
        drawValue(doc, val);
      });

      var checks = section.querySelectorAll('input[type="checkbox"]');
      if (checks.length > 0) {
        checks.forEach(function (cb) {
          var lbl = ''; var le = cb.closest('label') || cb.parentElement;
          if (le) lbl = le.textContent.trim();
          if (lbl) {
            needsNewPage(doc, 8);
            doc.setFontSize(9); doc.setFont('helvetica','normal'); doc.setTextColor(DARK[0], DARK[1], DARK[2]);
            doc.text((cb.checked ? '[x]' : '[ ]') + '  ' + lbl, MARGIN + 2, y + 3);
            y += 6;
          }
        });
        y += 3;
      }

      drawDivider(doc);
    });

    var standaloneCards = document.querySelectorAll('main > section.glass, main > .glass');
    standaloneCards.forEach(function (card) {
      var h = card.querySelector('h3, h2');
      var heading = h ? h.textContent.trim() : '';
      var body = '';
      card.querySelectorAll('p').forEach(function (p) { var t = p.textContent.trim(); if (t && t !== heading) body += (body ? ' ' : '') + t; });
      if (heading || body) drawCard(doc, heading, body);
    });

    drawFooter(doc);
    var fileName = pageTitle.replace(/[^a-zA-Z0-9 ]/g, '').replace(/\s+/g, '-') + '.pdf';
    doc.save(fileName);
  }
})();
